import{_ as t,a}from"./chunks/查询额度成功.wz9SQqrH.js";import{_ as o,o as d,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Adding a pCloud Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/pcloud.md","filePath":"en/upload/pcloud.md","lastUpdated":1781962217000}'),n={name:"en/upload/pcloud.md"};function i(r,e,c,p,h,u){return d(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="adding-a-pcloud-channel" tabindex="-1">Adding a pCloud Channel <a class="header-anchor" href="#adding-a-pcloud-channel" aria-label="Permalink to &quot;Adding a pCloud Channel&quot;">​</a></h1><h2 id="best-for" tabindex="-1">Best For <a class="header-anchor" href="#best-for" aria-label="Permalink to &quot;Best For&quot;">​</a></h2><ul><li>You have a pCloud account and want ImgBed to store images in pCloud.</li><li>You are comfortable using your pCloud account email and password as channel credentials.</li></ul><h2 id="what-you-need-first" tabindex="-1">What You Need First <a class="header-anchor" href="#what-you-need-first" aria-label="Permalink to &quot;What You Need First&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Why You Need It</th></tr></thead><tbody><tr><td>pCloud account email</td><td>Used to sign in to the pCloud API</td></tr><tr><td>pCloud password</td><td>Used to sign in to the pCloud API</td></tr><tr><td>API host</td><td>Defaults to <code>api.pcloud.com</code>. EU accounts can use <code>eapi.pcloud.com</code>.</td></tr><tr><td>Storage directory</td><td>Where files are stored. Defaults to <code>imgbed</code>.</td></tr></tbody></table><h2 id="where-to-add-it" tabindex="-1">Where To Add It <a class="header-anchor" href="#where-to-add-it" aria-label="Permalink to &quot;Where To Add It&quot;">​</a></h2><ol><li>Open System Settings.</li><li>Open Upload Settings.</li><li>Click <code>Add Channel</code> in the upper-right corner.</li><li>Choose <code>pCloud</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Identifies this pCloud channel, for example <code>Personal pCloud</code></td><td>Yes</td></tr><tr><td>Account email</td><td>Your pCloud login email</td><td>Yes</td></tr><tr><td>Password</td><td>Your pCloud password</td><td>Yes</td></tr><tr><td>API host</td><td>pCloud API host. Defaults to <code>api.pcloud.com</code>.</td><td>No</td></tr><tr><td>Storage directory</td><td>Directory used to store files. Defaults to <code>imgbed</code>.</td><td>No</td></tr></tbody></table><p>Choose the API host based on your account region:</p><table tabindex="0"><thead><tr><th>Account Region</th><th>API Host</th></tr></thead><tbody><tr><td>Default / US</td><td><code>api.pcloud.com</code></td></tr><tr><td>Europe</td><td><code>eapi.pcloud.com</code></td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Open Upload Settings.</li><li>Click <code>Add Channel</code>.</li><li>Choose <code>pCloud</code>.</li><li>Enter a channel name you can recognize.</li><li>Enter your pCloud account email.</li><li>Enter your pCloud password.</li><li>Keep the API host as <code>api.pcloud.com</code>, or use <code>eapi.pcloud.com</code> for EU accounts.</li><li>Keep the storage directory as <code>imgbed</code>, or change it to your preferred folder.</li><li>Save the channel.</li></ol><p><img src="'+t+'" alt="Configure channel" loading="lazy"></p><h2 id="how-to-verify-it" tabindex="-1">How To Verify It <a class="header-anchor" href="#how-to-verify-it" aria-label="Permalink to &quot;How To Verify It&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>The pCloud channel card appears after saving.</td></tr><tr><td>Channel switch</td><td>The switch on the card stays enabled.</td></tr><tr><td>Email display</td><td>The card shows the connected pCloud email.</td></tr><tr><td>Quota query</td><td>After a successful query, used and total capacity are displayed.</td></tr><tr><td>Upload test</td><td>A test image appears in the configured pCloud storage directory.</td></tr></tbody></table><p><img src="'+a+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="why-not-oauth2" tabindex="-1">Why Not OAuth2? <a class="header-anchor" href="#why-not-oauth2" aria-label="Permalink to &quot;Why Not OAuth2?&quot;">​</a></h3><p>pCloud OAuth2 is not self-service by default. You need to email pCloud and ask them to enable it.</p><p>The current pCloud OAuth2 flow also does not support the short-lived upload link workflow that ImgBed needs, so this channel uses account email and password login instead.</p><h3 id="which-api-host-should-i-use" tabindex="-1">Which API Host Should I Use? <a class="header-anchor" href="#which-api-host-should-i-use" aria-label="Permalink to &quot;Which API Host Should I Use?&quot;">​</a></h3><p>Default:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api.pcloud.com</span></span></code></pre></div><p>For EU accounts:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eapi.pcloud.com</span></span></code></pre></div><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Prepare your pCloud email and password</span></span>
<span class="line"><span>-&gt; Open Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; Choose pCloud</span></span>
<span class="line"><span>-&gt; Fill channel name / email / password</span></span>
<span class="line"><span>-&gt; Keep API host as api.pcloud.com unless your account is in Europe</span></span>
<span class="line"><span>-&gt; Keep storage directory as imgbed unless you need another folder</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Query quota</span></span>
<span class="line"><span>-&gt; Upload a test image</span></span></code></pre></div>`,28)])])}const f=o(n,[["render",i]]);export{m as __pageData,f as default};
